def normalize_phone(value):
    value = str(value or '').strip().replace(' ', '').replace('-', '')
    if not value or value == '0':
        return ''
    if value.startswith('+'):
        return value[:16]
    if value.startswith('0'):
        return f'+254{value[1:]}'[:16]
    return f'+254{value}'[:16]


def next_unique_number(used_numbers):
    while True:
        number = random.randint(100000000, 999999999)
        if number not in used_numbers:
            used_numbers.add(number)
            return number


def prepare_existing_data(apps, schema_editor):
    Appointment = apps.get_model('dasapp', 'Appointment')
    DoctorReg = apps.get_model('dasapp', 'DoctorReg')
