    used_numbers = set()
    occupied_slots = set()

    for appointment in Appointment.objects.order_by('id'):
        if not appointment.appointmentnumber or appointment.appointmentnumber in used_numbers:
            appointment.appointmentnumber = next_unique_number(used_numbers)
        else:
            used_numbers.add(appointment.appointmentnumber)

        appointment.mobilenumber = normalize_phone(appointment.mobilenumber)
        if appointment.status in ('1', 1):
            appointment.status = 'Approved'
        elif appointment.status in ('2', 2):
            appointment.status = 'Cancelled'
        elif appointment.status in ('3', 3):
            appointment.status = 'Completed'
        elif appointment.status not in ('0', 'Approved', 'Cancelled', 'Completed'):
            appointment.status = '0'
        if appointment.prescription == '0':
            appointment.prescription = ''
        if appointment.recommendedtest == '0':
            appointment.recommendedtest = ''

        slot = (
            appointment.doctor_id_id,
            appointment.date_of_appointment,
            appointment.time_of_appointment,
        )
        while slot in occupied_slots:
            appointment_datetime = datetime.combine(
                appointment.date_of_appointment,
                appointment.time_of_appointment,
            ) + timedelta(minutes=1)
            appointment.time_of_appointment = appointment_datetime.time()
            slot = (
                appointment.doctor_id_id,
                appointment.date_of_appointment,
                appointment.time_of_appointment,
            )
        occupied_slots.add(slot)

        appointment.save(update_fields=[
            'appointmentnumber',
            'mobilenumber',
            'status',
            'prescription',
            'recommendedtest',
            'time_of_appointment',
        ])

    for doctor in DoctorReg.objects.all():
        doctor.mobilenumber = normalize_phone(doctor.mobilenumber)
        doctor.save(update_fields=['mobilenumber'])

    for page in Page.objects.all():
        page.mobilenumber = normalize_phone(page.mobilenumber)
        page.save(update_fields=['mobilenumber'])


